  `bet_coin` decimal(8,2) DEFAULT NULL,
  `total_coin` decimal(10,2) DEFAULT NULL,
  `prev_balance` decimal(10,2) DEFAULT NULL,
  `cur_balance` decimal(10,2) DEFAULT NULL,
  `bet_status` enum('WIN','LOST','USER_CANCEL','CANCEL_ADMIN','MATCH_RUNNING','BET_RETURN') DEFAULT 'MATCH_RUNNING',
  `bet_type` enum('SINGLE_BET','MULTI_BET') DEFAULT 'SINGLE_BET',
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=143 DEFAULT CHARSET=utf8;
