--
-- Table structure for table `matchname`
--

DROP TABLE IF EXISTS `matchname`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `matchname` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `sportscategory_id` int DEFAULT NULL,
  `title` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `league_title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `desc` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `serial` int DEFAULT NULL,
  `notification` varchar(191) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `active_status` tinyint DEFAULT '1' COMMENT ' 1=In play, 2=Live Match, 3=Upcoming match, 4=Complete Match, 5=Match Cancelled, 6=Disabled, 7=Inactive, 8=Result Published | we will not using status field 3 & 4 no point ',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `status` int DEFAULT '1' COMMENT '1=active, 2=hide or inactive, 3=match end, 4=bet cancelled',
  `match_time_local` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `match_date_var` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `match_time_var` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `starting_time` datetime DEFAULT NULL,
  `end_time_local` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ending_time` datetime DEFAULT NULL,
  `min_bet_limit` int DEFAULT NULL,
  `max_bet_limit` int DEFAULT NULL,
  `has_question` tinyint DEFAULT '0',
  `ball_by_ball` enum('NO','YES') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'NO',
  `over_by_over` enum('NO','YES') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT 'NO',
  `total_over` tinyint DEFAULT '0',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=101 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

